        is.reset(); // should allow data to be re-read

        byte[] data2 = new byte[dataSize];
        is.read(data2);

        is.close();
        assertArrayEquals("bufferSize="+bufferSize+" dataSize="+dataSize, data1, data2); // data buffers should be identical
